(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('2dc8f4c4-367b-4fb9-affa-7578365eed9c', 'Which choice completes the text with the most logical and precise word or phrase?', 'In philosophy of biology, the standard view holds that early practitioners merely refined an inherited method; the more careful reading—one that attends to a qualification buried in a subordinate clause—suggests instead that they sought to table the method''s reach, bounding rather than extending it. Granting the surface impression of growth, the evidence nonetheless shows the practitioners working to table the very ambitions their successors would later celebrate, a restraint that the triumphalist chronology, attentive only to outcomes, cannot register.', 'passage', '[{"id":"A","text":"The word \"table,\" in its ordinary sense, means to detain or seize. This sense does not fit because nothing in the clause involves seizure or capture —a distinction the passage stages deliberately.","is_correct":false,"explanation":"[Collocation Decoy] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"B","text":"The word \"table,\" in a looser sense, means to encourage or advance. This sense does not fit because it reverses the restraint the qualifier establishes —a distinction the passage stages deliberately.","is_correct":false,"explanation":"[Over-Extrapolation] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"C","text":"The word \"table,\" in a connotative sense, means to celebrate openly. This sense does not fit because the passage''s tone is analytic, not celebratory —a distinction the passage stages deliberately.","is_correct":false,"explanation":"[Reverse Trap] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"The word \"table,\" in its specialized sense, means to set aside from consideration. This sense fits because the clause opposes restraint to the successors'' ambitions —a distinction the passage stages deliberately.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."}]'::jsonb, 'D', 'Logical Reconstruction:
Step 1: Identify the contrast: surface growth versus a buried qualification signalling restraint.
Step 2: Suppress the common senses of the word that collocate with the topic of progress.
Step 3: Select the rare sense that completes the restraint–ambition opposition precisely.
Step 4: Only "to set aside from consideration" satisfies the syntactic position of the blank.

Key Explanation: Choice D is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice A [Collocation Decoy]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice B [Over-Extrapolation]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice C [Reverse Trap]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of polysemous suppression: the blank requires the word''s rarest domain sense while three more common senses collocate naturally with the topic.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"vocabulary_in_context","rw_format":"passage_mc","challenge_key":"WIC"}'::jsonb, true, now(), now());
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, challenge_only, created_at, updated_at)
VALUES ('b62f370d-db42-4014-8edc-a8e106398d5f', 'Which choice best describes the overall structure of the text?', 'Within philosophy of biology, the codification of an oral repertoire has long been read as straightforward progress, a reading that the discipline''s founders—whose archives, only recently catalogued, complicate the received chronology—did much to entrench. What that account treats as teleonomy, however, the measured asymmetry reframes: the apparent advance, far from being intrinsic, was conditioned by an institutional canalization that the standard narrative cannot model. Granting that the correlation is genuine, one must still resist the inference that it is causal, for the same configuration recurs only under conditions the standard account leaves tacit.', 'passage', '[{"id":"A","text":"The text opens by foregrounding a conventional reading of its subject. It then endorses the critique outright, stopping at the concession without complicating it further —a distinction the passage stages deliberately, in the passage''s own terms.","is_correct":false,"explanation":"[Rhetorical Misclassification] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"B","text":"The text opens by foregrounding a conventional reading of its subject. It then identifies the structural reversal but misattributes it to the original theory rather than to the critic''s alternative —a distinction the passage stages deliberately.","is_correct":false,"explanation":"[Rhetorical Misclassification] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"C","text":"The text opens by foregrounding a conventional reading of its subject. It then proposes a wholly new alternative, treating the prior positions as superseded —a distinction the passage stages deliberately, given the stated qualifiers.","is_correct":false,"explanation":"[Over-Extrapolation] Grounded in passage language but fails on a specific qualifier in its second sentence."},{"id":"D","text":"The text opens by foregrounding a conventional reading of its subject. It then concedes part of a critique only to show that the critic''s own alternative reproduces the flaw, undermining the critique on structural grounds —a distinction the passage stages deliberately.","is_correct":true,"explanation":"Correct: its second sentence is the only one that satisfies the discriminating condition."}]'::jsonb, 'D', 'Logical Reconstruction:
Step 1: Move 1: a conventional theory and its critique are introduced.
Step 2: Move 2: the critique is partially, not fully, conceded.
Step 3: Move 3: the critic''s own alternative is shown to replicate the flaw under a condition.
Step 4: The correct choice names that structural self-undermining; others stop at the concession or invent a new proposal.

Key Explanation: Choice D is the only option whose second sentence survives the discriminating step above; the others are grounded in real passage language but fail a specific qualifier.

Distractor Analysis:
- Choice A [Rhetorical Misclassification]: a 720–740 student is drawn to its accurate first sentence, but its second sentence imports a relationship the passage withholds — exactly the habit this trap exploits.
- Choice B [Rhetorical Misclassification]: a 720–740 student is drawn to its accurate first sentence, but its second sentence satisfies only part of the stated condition — exactly the habit this trap exploits.
- Choice C [Over-Extrapolation]: a 720–740 student is drawn to its accurate first sentence, but its second sentence extends beyond the passage''s qualifiers — exactly the habit this trap exploits.

Difficulty Justification: This item is Challenge-tier because of non-linear three-move rhetorical concession requiring structural discrimination between qualifying an endorsement and conceding a structural limitation.

Score Prediction: A student scoring 750+ on DSAT R&W should answer this item correctly with deliberate reasoning; a student scoring 720–740 should find it genuinely difficult even after a careful first pass.', NULL, 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"tier":"challenge","challenge_tier":true,"challenged_problem":true,"difficulty_tier":"challenge","explanation_v2":true,"generator":"generate-challenge-bank.mjs","rw_subtype":"structure","rw_format":"passage_mc","challenge_key":"TSP"}'::jsonb, true, now(), now());
